import{_ as a,o as s,c as n,al as i}from"./chunks/framework.BOATtE-F.js";const u=JSON.parse('{"title":"Document Structure","description":"","frontmatter":{"prev":{"text":"Getting Started","link":"/en/posts/docs/ageratum/01-getting-started"},"next":{"text":"Markdown Syntax Reference","link":"/en/posts/docs/ageratum/03-markdown-syntax"}},"headers":[],"relativePath":"en/posts/docs/ageratum/02-document-structure.md","filePath":"en/posts/docs/ageratum/02-document-structure.md","lastUpdated":1774291294000}'),t={name:"en/posts/docs/ageratum/02-document-structure.md"};function l(r,e,o,d,p,c){return s(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="document-structure" tabindex="-1">Document Structure <a class="header-anchor" href="#document-structure" aria-label="Permalink to “Document Structure”">​</a></h1><p>This document explains Ageratum&#39;s resource pack layout, path conventions, and Front Matter syntax.</p><hr><h2 id="resource-pack-directory-layout" tabindex="-1">Resource Pack Directory Layout <a class="header-anchor" href="#resource-pack-directory-layout" aria-label="Permalink to “Resource Pack Directory Layout”">​</a></h2><p>Ageratum documents are stored under the standard Minecraft resource pack <code>assets/</code> directory:</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>assets/</span></span>
<span class="line"><span>└── &lt;namespace&gt;/</span></span>
<span class="line"><span>    └── ageratum/</span></span>
<span class="line"><span>        ├── en_us/              ← Default language (required)</span></span>
<span class="line"><span>        │   ├── index.md        ← Home page document</span></span>
<span class="line"><span>        │   ├── &lt;file&gt;.md</span></span>
<span class="line"><span>        │   └── &lt;subdir&gt;/</span></span>
<span class="line"><span>        │       └── &lt;file&gt;.md</span></span>
<span class="line"><span>        ├── zh_cn/              ← Chinese (optional)</span></span>
<span class="line"><span>        │   └── ...</span></span>
<span class="line"><span>        └── &lt;any_lang&gt;/         ← Any language code (optional)</span></span>
<span class="line"><span>            └── ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h3 id="namespaces" tabindex="-1">Namespaces <a class="header-anchor" href="#namespaces" aria-label="Permalink to “Namespaces”">​</a></h3><ul><li><code>&lt;namespace&gt;</code> is typically the same as your mod ID.</li><li>Ageratum&#39;s own documentation namespace is <code>ageratum</code>.</li><li>Multiple namespaces can coexist without interference.</li></ul><h3 id="language-codes" tabindex="-1">Language Codes <a class="header-anchor" href="#language-codes" aria-label="Permalink to “Language Codes”">​</a></h3><ul><li>Language codes follow the Minecraft standard (e.g. <code>en_us</code>, <code>zh_cn</code>, <code>ja_jp</code>).</li><li>Resolution order: <strong>client&#39;s current language</strong> → <strong><code>en_us</code> (fallback)</strong>.</li><li>Language codes are case-insensitive; hyphens <code>-</code> are automatically converted to underscores <code>_</code>.</li></ul><hr><h2 id="file-path-conventions" tabindex="-1">File Path Conventions <a class="header-anchor" href="#file-path-conventions" aria-label="Permalink to “File Path Conventions”">​</a></h2><h3 id="valid-path-examples" tabindex="-1">Valid Path Examples <a class="header-anchor" href="#valid-path-examples" aria-label="Permalink to “Valid Path Examples”">​</a></h3><table tabindex="0"><thead><tr><th>Resource Location</th><th>Description</th></tr></thead><tbody><tr><td><code>mymod:ageratum/en_us/index.md</code></td><td>English home page</td></tr><tr><td><code>mymod:ageratum/zh_cn/index.md</code></td><td>Chinese home page</td></tr><tr><td><code>mymod:ageratum/en_us/tutorial/basics.md</code></td><td>File in subdirectory</td></tr><tr><td><code>mymod:ageratum/en_us/faq.md</code></td><td>Top-level document</td></tr></tbody></table><h3 id="path-normalization-rules" tabindex="-1">Path Normalization Rules <a class="header-anchor" href="#path-normalization-rules" aria-label="Permalink to “Path Normalization Rules”">​</a></h3><p><code>GuideDocumentLoader</code> automatically applies the following normalization:</p><ol><li><strong>Empty path</strong> → defaults to <code>index</code> (home page)</li><li><strong>Extension completion</strong>: <code>.md</code> is appended if not already present</li><li><strong>Path separator</strong>: backslashes <code>\\</code> are converted to forward slashes <code>/</code></li><li><strong>Leading slash removal</strong>: <code>/guide</code> → <code>guide</code></li><li><strong>Language code normalization</strong>: uppercased to lowercase, <code>-</code> → <code>_</code></li></ol><h3 id="command-path-examples" tabindex="-1">Command Path Examples <a class="header-anchor" href="#command-path-examples" aria-label="Permalink to “Command Path Examples”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/ageratum mymod                     → assets/mymod/ageratum/&lt;lang&gt;/index.md</span></span>
<span class="line"><span>/ageratum mymod guide               → assets/mymod/ageratum/&lt;lang&gt;/guide.md</span></span>
<span class="line"><span>/ageratum mymod tutorial/basics     → assets/mymod/ageratum/&lt;lang&gt;/tutorial/basics.md</span></span>
<span class="line"><span>/ageratum mymod zh_cn/advanced      → assets/mymod/ageratum/zh_cn/advanced.md</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><hr><h2 id="front-matter" tabindex="-1">Front Matter <a class="header-anchor" href="#front-matter" aria-label="Permalink to “Front Matter”">​</a></h2><p>Ageratum supports YAML-style Front Matter for document metadata. It must appear at the very beginning of the file, delimited by <code>---</code>:</p><div class="language-markdown line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">---</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">title: &quot;My Document Title&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">navigation:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  title: &quot;Sidebar Title&quot;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># Document body content</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h3 id="supported-fields" tabindex="-1">Supported Fields <a class="header-anchor" href="#supported-fields" aria-label="Permalink to “Supported Fields”">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>title</code></td><td><code>string</code></td><td>Document title (overrides first heading)</td></tr><tr><td><code>navigation.title</code></td><td><code>string</code></td><td>Title shown in the sidebar navigation (takes priority over <code>title</code>)</td></tr></tbody></table><h3 id="title-resolution-priority" tabindex="-1">Title Resolution Priority <a class="header-anchor" href="#title-resolution-priority" aria-label="Permalink to “Title Resolution Priority”">​</a></h3><p>Ageratum determines the document title in the following order:</p><ol><li><code>navigation.title</code> (Front Matter)</li><li><code>title</code> (Front Matter)</li><li>First level-1 heading (<code># Heading</code>) in the document</li><li>File name (without extension)</li></ol><hr><h2 id="navigation-tree-structure" tabindex="-1">Navigation Tree Structure <a class="header-anchor" href="#navigation-tree-structure" aria-label="Permalink to “Navigation Tree Structure”">​</a></h2><p>Ageratum automatically scans all <code>.md</code> files on resource pack load and builds a two-level navigation tree displayed in the GUI sidebar.</p><h3 id="navigation-tree-rules" tabindex="-1">Navigation Tree Rules <a class="header-anchor" href="#navigation-tree-rules" aria-label="Permalink to “Navigation Tree Rules”">​</a></h3><ul><li><strong>Directories</strong>: correspond to filesystem subdirectories</li><li><strong><code>index.md</code></strong>: serves as the index page for a directory, displayed on the directory entry</li><li>The tree shows at most two levels (top-level directories + subdirectories)</li><li>Files are sorted alphabetically by file name</li><li>Directories are sorted alphabetically by directory name</li></ul><h3 id="example-structure" tabindex="-1">Example Structure <a class="header-anchor" href="#example-structure" aria-label="Permalink to “Example Structure”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>assets/mymod/ageratum/en_us/</span></span>
<span class="line"><span>├── index.md          → Root-level document (title from document)</span></span>
<span class="line"><span>├── guide.md          → Root-level document</span></span>
<span class="line"><span>├── faq.md            → Root-level document</span></span>
<span class="line"><span>└── tutorial/</span></span>
<span class="line"><span>    ├── index.md      → Index page for the tutorial directory</span></span>
<span class="line"><span>    ├── basics.md     → Document under tutorial/</span></span>
<span class="line"><span>    └── advanced.md   → Document under tutorial/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>Sidebar rendering result (schematic):</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>[Home]</span></span>
<span class="line"><span>[Guide]</span></span>
<span class="line"><span>[FAQ]</span></span>
<span class="line"><span>▼ [Tutorial]</span></span>
<span class="line"><span>   [Tutorial Index]</span></span>
<span class="line"><span>   [Basics]</span></span>
<span class="line"><span>   [Advanced]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><hr><h2 id="image-resources" tabindex="-1">Image Resources <a class="header-anchor" href="#image-resources" aria-label="Permalink to “Image Resources”">​</a></h2><p>Images referenced in documents use <code>namespace:path</code> format, corresponding to <code>assets/&lt;namespace&gt;/textures/&lt;path&gt;</code> files.</p><div class="language-markdown line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">![</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">Description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#24292E;--shiki-light-text-decoration:underline;--shiki-dark:#E1E4E8;--shiki-dark-text-decoration:underline;">mymod:gui/my_image.png</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">![</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">Description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#24292E;--shiki-light-text-decoration:underline;--shiki-dark:#E1E4E8;--shiki-dark-text-decoration:underline;">ageratum:gui/guide/guide.png</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Images <strong>must occupy their own line</strong> in the document. Inline images (within a paragraph) are not currently supported.</p>`,42)])])}const m=a(t,[["render",l]]);export{u as __pageData,m as default};
